class Solution:
    def findingUsersActiveMinutes(self, logs, k):
        users = {}
        for uid, t in logs:
            if uid not in users:
                users[uid] = []
            if t not in users[uid]:
                users[uid].append(t)
        ans = [0] * k
        for uid, mins in users.items():
            uam = len(mins)
            if 1 <= uam <= k:
                ans[uam - 1] += 1
        return ans

