class Solution:
    def findingUsersActiveMinutes(self, logs, k):
        from collections import defaultdict
        users = defaultdict(set)
        for uid, t in logs:
            users[uid].add(t)
        ans = [0] * k
        for s in users.values():
            ans[len(s) - 1] += 1
        return ans

