var findingUsersActiveMinutes = function(logs, k) {
    const users = new Map();
    for (const [uid, t] of logs) {
        if (!users.has(uid)) users.set(uid, new Set());
        users.get(uid).add(t);
    }
    const ans = new Array(k).fill(0);
    for (const s of users.values()) {
        ans[s.size - 1]++;
    }
    return ans;
};
